import scala.xml._
import scala.util.Try
import akka.http.scaladsl.server.Directives._
import akka.http.scaladsl.model.StatusCodes
import akka.http.scaladsl.server.Route

object ConfigService {
  def extractSettings(xmlString: String): Try[Map[String, String]] = Try {
    val xml = XML.loadString(xmlString)
    (xml \\ "setting").map { setting =>
      val key = (setting \ "@key").text
      val value = setting.text
      key -> value
    }.toMap
  }

  val route: Route = path("parse-config") {
    post {
      entity(as[String]) { xmlString =>
        extractSettings(xmlString) match {
          case scala.util.Success(settings) =>
            complete(StatusCodes.OK, settings.toString)
          case scala.util.Failure(ex) =>
            complete(StatusCodes.BadRequest, s"Failed to parse XML: ${ex.getMessage}")
        }
      }
    }
  }
}